request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?block ?name ?beh ?behName WHERE {
  ?block rdf:type vocab:block .
  ?block vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(?name), "APS"))

  OPTIONAL {
    ?block vocab:BehavioredClassifier_ownedBehavior ?beh .
    ?beh vocab:NamedElement_name ?behName .
  }
}
LIMIT 50
